signature.raw:
VkResult vkWriteSamplerDescriptorsEXT(
 VkDevice device,
 uint32_t samplerCount,
 const VkSamplerCreateInfo* pSamplers,
 const VkHostAddressRangeEXT* pDescriptors);

details.example:
